// --- types.d.ts ---
// types.d.ts

/**
 * Weather Card Component - Type Definitions
 */

/**
 * Represents a single day in the 5-day forecast
 */
export interface ForecastDay {
  day: string;
  icon: string;
  high: number;
  low: number;
}

/**
 * The main component props for the weather card container
 */
export interface Props {
  city: string;
  temperature: number;
  condition: string;
  humidity: number;
  windSpeed: number;
  unit?: string;
  forecast: ForecastDay[];
}

/**
 * The return type for custom hooks that process weather data
 */
export interface HookReturn {
  getWeatherDescription: () => string;
  getConditionEmoji: () => string;
  formattedTemperature: string;
}

/**
 * Props for the CurrentWeather sub-component
 */
export interface CurrentWeatherProps {
  city: string;
  temperature: string;
  condition: string;
  conditionEmoji: string;
}

/**
 * Props for the WeatherDetails sub-component that displays supplementary metrics
 */
export interface WeatherDetailsProps {
  humidity: number;
  windSpeed: number;
}

/**
 * Props for the DetailRow sub-component (reusable row for displaying label-value pairs)
 */
export interface DetailRowProps {
  label: string;
  value: string;
  icon?: string;
}

/**
 * Props for a single ForecastItem sub-component
 */
export interface ForecastItemProps {
  day: string;
  icon: string;
  high: number;
  low: number;
}

/**
 * Props for the ForecastStrip container component
 */
export interface ForecastStripProps {
  forecast: ForecastDay[];
}


// --- constants.ts ---
// constants.ts

/**
 * Weather condition to emoji mapping
 * Maps lowercase weather condition strings to appropriate emoji characters
 */
export const WEATHER_CONDITION_EMOJI_MAP: Record<string, string> = {
  sunny: '☀️',
  clear: '☀️',
  cloudy: '☁️',
  overcast: '☁️',
  rainy: '🌧️',
  rain: '🌧️',
  snowy: '❄️',
  snow: '❄️',
  windy: '💨',
  'partly-cloudy': '⛅',
  'partly cloudy': '⛅',
  thunderstorm: '🌩️',
  'thunderstorm': '⛈️',
  night: '🌙',
  default: '🌡️',
};

/**
 * UI Label Constants
 */
export const HUMIDITY_LABEL = 'Humidity';
export const WIND_SPEED_LABEL = 'Wind Speed';

export const DEFAULT_UNIT = '°C';


// --- hooks.ts ---
// hooks.ts
import { useMemo } from 'react';
import type { Props, HookReturn } from './types';

/**
 * Custom hook for processing and formatting weather card data
 * Validates props, formats temperature, maps conditions to emojis,
 * and provides weather descriptions
 *
 * @param props - Weather data props to process
 * @returns Object containing formatted temperature, emoji getter, and description getter
 */
export function useWeatherCard(props: Props): HookReturn {
  return useMemo(() => {
    // Props validation
    validateProps(props);

    // Format temperature with unit
    const unit = props.unit || '°C';
    const formattedTemperature = `${Math.round(props.temperature)}${unit}`;

    /**
     * Maps weather condition strings to corresponding emoji representations
     * Handles case-insensitive matching and provides a fallback emoji
     *
     * @returns Weather emoji string
     */
    const getConditionEmoji = (): string => {
      const condition = props.condition.toLowerCase().trim();

      const conditionMap: Record<string, string> = {
        sunny: '☀️',
        clear: '☀️',
        'partly clear': '☀️',
        cloudy: '☁️',
        overcast: '☁️',
        'partly cloudy': '☁️',
        rainy: '🌧️',
        rain: '🌧️',
        'light rain': '🌧️',
        snowy: '❄️',
        snow: '❄️',
        stormy: '⛈️',
        thunderstorm: '⛈️',
        storm: '⛈️',
        foggy: '🌫️',
        fog: '🌫️',
        mist: '🌫️',
      };

      return conditionMap[condition] || '🌡️';
    };

    /**
     * Generates a human-readable weather description
     * Combines condition with humidity and wind speed metrics
     *
     * @returns Formatted weather description string
     */
    const getWeatherDescription = (): string => {
      const condition = props.condition.trim();
      const capitalizedCondition =
        condition.charAt(0).toUpperCase() + condition.slice(1).toLowerCase();

      return `${capitalizedCondition} with ${props.humidity}% humidity and ${props.windSpeed} km/h wind`;
    };

    return {
      getWeatherDescription,
      getConditionEmoji,
      formattedTemperature,
    };
  }, [props]);
}

/**
 * Validates all required props and their values
 * Logs console warnings for invalid props but does not throw errors
 *
 * @param props - Props object to validate
 */
function validateProps(props: Props): void {
  // Validate required fields exist
  if (!props.city || typeof props.city !== 'string') {
    console.warn('Invalid or missing city prop');
  }

  if (!Number.isFinite(props.temperature)) {
    console.warn('Invalid temperature: must be a finite number');
  }

  if (!props.condition || typeof props.condition !== 'string') {
    console.warn('Invalid or missing condition prop');
  }

  if (
    typeof props.humidity !== 'number' ||
    props.humidity < 0 ||
    props.humidity > 100
  ) {
    console.warn('Invalid humidity: must be a number between 0-100');
  }

  if (typeof props.windSpeed !== 'number' || props.windSpeed < 0) {
    console.warn('Invalid windSpeed: must be a non-negative number');
  }

  if (!Array.isArray(props.forecast) || props.forecast.length < 1) {
    console.warn('Invalid forecast: must be an array with at least 1 item');
  }

  // Validate unit if provided
  if (props.unit && typeof props.unit !== 'string') {
    console.warn('Invalid unit: must be a string');
  }
}


