// components/CurrentWeather.tsx
import React from 'react';
import { Stack, Box, Heading, Text } from '@ggui-ai/design/primitives';
import type { CurrentWeatherProps } from './types';

export const CurrentWeather: React.FC<CurrentWeatherProps> = ({
  city,
  temperature,
  condition,
  conditionEmoji,
}) => {
  return (
    <Box
      paddingY={24}
      paddingX={16}
      style={{
        textAlign: 'center',
      }}
    >
      <Stack gap={16} align="center">
        <Heading
          level={6}
          color="var(--ggui-color-onSurfaceVariant, #52525b)"
        >
          {city}
        </Heading>
        <Heading level={1} color="var(--ggui-color-onSurface, #18181b)">
          {temperature}
        </Heading>
        <Stack direction="horizontal" gap={8} align="center" justify="center">
          <Text size="2xl">{conditionEmoji}</Text>
          <Text variant="body" color="var(--ggui-color-onSurface, #18181b)">
            {condition}
          </Text>
        </Stack>
      </Stack>
    </Box>
  );
};


