// components/DetailRow.tsx
import { Stack, Text, Icon } from '@ggui-ai/design/primitives';
import type { DetailRowProps } from './types';

/**
 * DetailRow Component
 *
 * Renders a single detail row displaying a label-value pair (e.g., Humidity: 65%)
 * with optional icon support. Used within the WeatherDetails section.
 *
 * @param label - The detail label (e.g., "Humidity")
 * @param value - The detail value (e.g., "65%")
 * @param icon - Optional icon name or emoji string
 */
export default function DetailRow({ label, value, icon }: DetailRowProps) {
  return (
    <Stack
      direction="horizontal"
      align="center"
      gap={`var(--ggui-spacing-2, 8px)`}
    >
      {icon && (
        <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
          {icon}
        </Text>
      )}
      <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
        {label}
      </Text>
      <Text variant="body" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
        {value}
      </Text>
    </Stack>
  );
}


// --- components/WeatherDetails.tsx ---
// components/WeatherDetails.tsx
import { WeatherDetailsProps } from '@/types';
import { Stack, Text } from '@ggui-ai/design/primitives';
import DetailRow from './DetailRow';

export default function WeatherDetails({ humidity, windSpeed }: WeatherDetailsProps) {
  return (
    <Stack
      direction="vertical"
      gap={8}
      style={{
        padding: 'var(--ggui-spacing-4, 16px)',
      }}
    >
      <Text variant="overline" color="var(--ggui-color-onSurfaceVariant, #52525b)">
        Details
      </Text>
      <DetailRow label="Humidity" value={`${humidity}%`} icon="💧" />
      <DetailRow label="Wind Speed" value={`${windSpeed} km/h`} icon="💨" />
    </Stack>
  );
}


