// components/ForecastItem.tsx
import { Card, Stack, Text } from '@ggui-ai/design/primitives';
import type { ForecastItemProps } from '../types';

export default function ForecastItem({
  day,
  icon,
  high,
  low,
}: ForecastItemProps) {
  const roundedHigh = Math.round(high);
  const roundedLow = Math.round(low);

  return (
    <Card
      padding={8}
      shadow="none"
      border={true}
      radius="md"
      style={{
        flex: '0 0 90px',
        minHeight: '120px',
        display: 'flex',
        flexDirection: 'column',
      }}
    >
      <Stack
        direction="vertical"
        gap={4}
        align="center"
        justify="start"
        style={{ height: '100%' }}
      >
        <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
          {day}
        </Text>
        <div style={{ fontSize: '24px', lineHeight: 1 }}>
          {icon}
        </div>
        <Text variant="bodySmall" color="var(--ggui-color-onSurface, #18181b)">
          {roundedHigh}° / <span style={{ color: 'var(--ggui-color-onSurfaceVariant, #52525b)' }}>{roundedLow}°</span>
        </Text>
      </Stack>
    </Card>
  );
}


// --- components/ForecastStrip.tsx ---
// components/ForecastStrip.tsx
import { Stack } from '@ggui-ai/design/primitives';
import { ForecastItem } from './ForecastItem';
import type { ForecastStripProps } from '../types';

/**
 * ForecastStrip Component
 * 
 * Renders a horizontally scrollable strip of 5-day forecast items.
 * Uses Stack with horizontal direction and native CSS scrolling.
 */
export function ForecastStrip({ forecast }: ForecastStripProps) {
  // Handle empty forecast array
  if (!forecast || forecast.length === 0) {
    return null;
  }

  return (
    <div
      style={{
        overflowX: 'auto',
        overflowY: 'hidden',
        padding: 'var(--ggui-spacing-4, 16px)',
        minHeight: '140px',
      }}
    >
      <Stack direction="horizontal" gap="var(--ggui-spacing-2, 8px)" align="center">
        {forecast.map((day) => (
          <div key={day.day} style={{ flexShrink: 0, width: '85px' }}>
            <ForecastItem day={day.day} icon={day.icon} high={day.high} low={day.low} />
          </div>
        ))}
      </Stack>
    </div>
  );
}


// --- ui.tsx ---
// ui.tsx
import { Card, Stack, Divider } from '@ggui-ai/design/primitives';

import CurrentWeather from './components/CurrentWeather';
import WeatherDetails from './components/WeatherDetails';
import ForecastStrip from './components/ForecastStrip';

import { useWeather } from './hooks';

import type { Props } from './types';

export default function Component(props: Props): JSX.Element {
  // Call hook at component top
  const { formattedTemperature, getConditionEmoji } = useWeather(props);

  return (
    <Card
      padding="var(--ggui-spacing-6, 24px)"
      shadow="md"
      radius="lg"
      border={true}
    >
      <Stack
        direction="vertical"
        gap="var(--ggui-spacing-4, 16px)"
        align="stretch"
      >
        {/* Current Weather Section */}
        <CurrentWeather
          city={props.city}
          temperature={formattedTemperature}
          condition={props.condition}
          conditionEmoji={getConditionEmoji()}
        />

        {/* Divider */}
        <Divider
          orientation="horizontal"
          margin="var(--ggui-spacing-2, 8px)"
          color="var(--ggui-color-outline, #d4d4d8)"
        />

        {/* Weather Details Section */}
        <WeatherDetails
          humidity={props.humidity}
          windSpeed={props.windSpeed}
        />

        {/* Divider */}
        <Divider
          orientation="horizontal"
          margin="var(--ggui-spacing-2, 8px)"
          color="var(--ggui-color-outline, #d4d4d8)"
        />

        {/* Forecast Strip Section */}
        <ForecastStrip forecast={props.forecast} />
      </Stack>
    </Card>
  );
}


// --- render.tsx ---
// render.tsx
import React from 'react';
import { Props } from './types';
import { useWeatherCard } from './useWeatherCard';
import { Component as UI } from './ui';

const WeatherCardRender: React.FC<Props> = (props) => {
  const {
    getWeatherDescription,
    getConditionEmoji,
    formattedTemperature,
  } = useWeatherCard(props);

  return (
    <UI
      city={props.city}
      temperature={formattedTemperature}
      condition={props.condition}
      conditionEmoji={getConditionEmoji()}
      humidity={props.humidity}
      windSpeed={props.windSpeed}
      forecast={props.forecast}
    />
  );
};

export default WeatherCardRender;


// --- entrypoint.tsx ---
// entrypoint.tsx — wires hooks + component, export default
import React from 'react';
import type { Props } from './types';
import { Component } from './components/index';

export default function Entrypoint(props: Props) {
  return <Component {...props} />;
}
